  private _get33cRiskProgress(): number {
    return Math.round(this._33cRiskAssessmentWorkflow.filter(s => s.status === 'completed').length / this._33cRiskAssessmentWorkflow.length * 100);
  }

  private _get33cTreatmentSummary(): {total: number; approved: number; avgReduction: number; investment: string} {
    const a = this._33cTreatmentOptions.filter(r => r.status === 'approved').length;
    const avg = this._33cTreatmentOptions.reduce((s, r) => s + ((r.before - r.after) / r.before * 100), 0) / this._33cTreatmentOptions.length;
    return {total: this._33cTreatmentOptions.length, approved: a, avgReduction: Math.round(avg), investment: '$1.125M annually'};
  }

  private _get33cRuleSummary(): {total: number; passing: number; failing: number; avgRate: number; violations: number} {
    const p = this._33cComplianceRules.filter(r => r.result === 'pass').length;
    const f = this._33cComplianceRules.filter(r => r.result === 'fail').length;
    const avg = this._33cComplianceRules.reduce((s, r) => s + r.passRate, 0) / this._33cComplianceRules.length;
    const v = this._33cComplianceRules.reduce((s, r) => s + r.violations, 0);
    return {total: this._33cComplianceRules.length, passing: p, failing: f, avgRate: Math.round(avg * 10) / 10, violations: v};
  }

  private _get33cPipelineStats(): {positions: number; applicants: number; interviewing: number; offers: number; critical: number} {
    const t = this._33cTalentPositions.length;
    const a = this._33cTalentPositions.reduce((s, p) => s + p.applicants, 0);
    const i = this._33cTalentPositions.reduce((s, p) => s + p.interviews, 0);
    const o = this._33cTalentPositions.reduce((s, p) => s + p.offers, 0);
    const c = this._33cTalentPositions.filter(x => x.urgency === 'critical').length;
    return {positions: t, applicants: a, interviewing: i, offers: o, critical: c};
  }

  private _get33cMetricTrends(): {improving: number; stable: number; total: number} {
    const imp = this._33cMetricsDashboard.filter(m => m.trend === 'improving').length;
    const stb = this._33cMetricsDashboard.filter(m => m.trend === 'stable').length;
    return {improving: imp, stable: stb, total: this._33cMetricsDashboard.length};
  }

  private _get33cArchScore(): {total: number; passed: number; failed: number; partial: number; score: number} {
    const p = this._33cArchReview.filter(c => c.status === 'pass').length;
    const f = this._33cArchReview.filter(c => c.status === 'fail').length;
    const pa = this._33cArchReview.filter(c => c.status === 'partial').length;
    return {total: this._33cArchReview.length, passed: p, failed: f, partial: pa, score: Math.round((p / this._33cArchReview.length) * 100)};
  }


