  private _getz33cScenarioSummary(): {total: number; critical: number; high: number; drilled: number; avgRiskScore: number} {
    const crit = this._z33cIncidentScenarios.filter(s => s.impact === 'Critical').length;
    const high = this._z33cIncidentScenarios.filter(s => s.impact === 'High').length;
    const avg = this._z33cIncidentScenarios.reduce((s, x) => s + x.riskScore, 0) / this._z33cIncidentScenarios.length;
    return {total: this._z33cIncidentScenarios.length, critical: crit, high: high, drilled: this._z33cIncidentScenarios.length, avgRiskScore: Math.round(avg)};
  }

  private _getz33cVendorRiskSummary(): {total: number; approved: number; conditional: number; remediation: number; avgScore: number} {
    const approved = this._z33cThirdPartyRiskData.filter(v => v.status === 'approved').length;
    const cond = this._z33cThirdPartyRiskData.filter(v => v.status === 'conditional').length;
    const rem = this._z33cThirdPartyRiskData.filter(v => v.status === 'remediation_required').length;
    const avg = this._z33cThirdPartyRiskData.reduce((s, v) => s + v.riskScore, 0) / this._z33cThirdPartyRiskData.length;
    return {total: this._z33cThirdPartyRiskData.length, approved, conditional: cond, remediation: rem, avgScore: Math.round(avg)};
  }

  private _getz33cTrainingSummary(): {total: number; avgCompletion: number; avgScore: number; overdueUpdates: number} {
    const avgComp = this._z33cSecurityTrainingCatalog.reduce((s, t) => s + t.completionRate, 0) / this._z33cSecurityTrainingCatalog.length;
    const avgScore = this._z33cSecurityTrainingCatalog.filter(t => t.avgScore > 0).reduce((s, t) => s + t.avgScore, 0) / this._z33cSecurityTrainingCatalog.filter(t => t.avgScore > 0).length;
    return {total: this._z33cSecurityTrainingCatalog.length, avgCompletion: Math.round(avgComp * 10) / 10, avgScore: Math.round(avgScore), overdueUpdates: 0};
  }

  private _getz33cToolHealthSummary(): {total: number; healthy: number; degraded: number; annualCost: string} {
    const healthy = this._z33cSecurityToolInventory.filter(t => t.health === 'healthy').length;
    const degraded = this._z33cSecurityToolInventory.filter(t => t.health === 'degraded').length;
    const cost = this._z33cSecurityToolInventory.reduce((s, t) => s + parseInt(t.annualCost.replace(/[^0-9]/g, '')), 0);
    return {total: this._z33cSecurityToolInventory.length, healthy, degraded, annualCost: '$' + (cost / 1000).toFixed(0) + 'K'};
  }


