  private _renderArchCompliance() {
    const avgScore = Math.round(this._archPrinciples.reduce((a, p) => a + p.score, 0) / this._archPrinciples.length);
    return html`
      <div class="ac-container">
        <div class="ac-header">
          <h4>Architecture Compliance</h4>
          <div class="ac-overall" style="color: ${avgScore >= 80 ? '#22c55e' : avgScore >= 70 ? '#f59e0b' : '#ef4444'}">
            Overall: <strong>${avgScore}/100</strong>
          </div>
        </div>
        <div class="ac-principles-grid">
          ${this._archPrinciples.map(p => html`
            <div class="ac-principle-card">
              <div class="ac-p-name">${p.name}</div>
              <div class="ac-p-score-bar">
                <div class="ac-p-bar" style="width: ${p.score}%; background: ${p.score >= 80 ? '#22c55e' : p.score >= 70 ? '#f59e0b' : '#ef4444'}"></div>
              </div>
              <div class="ac-p-meta">
                <span class="ac-p-score">${p.score}</span>
                <span class="ac-p-trend ${p.trend}">${p.trend === 'up' ? '&#9650;' : p.trend === 'down' ? '&#9660;' : '='}</span>
                <span class="ac-p-finding">${p.finding}</span>
              </div>
            </div>
          `)}
        </div>
        <div class="ac-patterns">
          <h5>Design Pattern Adherence</h5>
          ${[
            { name: 'API Gateway', adherence: 92 },
            { name: 'Service Mesh', adherence: 58 },
            { name: 'Vault Integration', adherence: 75 },
            { name: 'Circuit Breaker', adherence: 84 },
            { name: 'Rate Limiting', adherence: 88 },
            { name: 'Input Validation', adherence: 79 },
          ].map(dp => html`<div class="ac-dp-row">
            <span class="ac-dp-name">${dp.name}</span>
            <div class="ac-dp-bar-container">
              <div class="ac-dp-bar" style="width: ${dp.adherence}%; background: ${dp.adherence >= 80 ? '#22c55e' : dp.adherence >= 60 ? '#f59e0b' : '#ef4444'}"></div>
            </div>
            <span class="ac-dp-score">${dp.adherence}%</span>
          </div>`)}
        </div>
        <div class="ac-techdebt">
          <h5>Technical Debt Tracking</h5>
          ${this._archTechDebt.map(td => html`<div class="ac-td-row">
            <span class="ac-td-severity ${td.severity}">${td.severity}</span>
            <span class="ac-td-name">${td.name}</span>
            <span class="ac-td-effort">${td.effort}</span>
            <span class="ac-td-impact">${td.impact}</span>
          </div>`)}
        </div>
      </div>`;
  }

